/// GET v2/{+parent}/sites
/// Lists all the sites available in an account.
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `adsense_accounts_sites_list_execute()` to send, or `adsense_accounts_sites_list` for simplest API.

pub fn adsense_accounts_sites_list_builder(
    client: &SimpleHttpClient,
    parent: &str,
    pageSize: Option<i32>,
    pageToken: Option<&str>,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {

    // Build URL
    let url = format!(
        "https://api.example.comv2/{+parent}/sites",
        parent,
    );

    // Build request
    client.get(&url)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))

        .query(
            "pageSize",
            pageSize.as_ref().map(|s| s.to_string()).unwrap_or_default().as_str(),
        )

        .query(
            "pageToken",
            pageToken.as_ref().map(|s| s.to_string()).unwrap_or_default().as_str(),
        )
}

